import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    try:
        user_input = input("Enter a command: ").strip()

        if not user_input:
            print("Error: No command provided")
            return

        # Validate command - only allow alphanumeric, common command characters, and spaces
        allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 ._-/')
        if not all(c in allowed_chars for c in user_input):
            print("Error: Invalid characters in command")
            return

        # Use shlex to safely parse the command into a list
        command_parts = shlex.split(user_input)

        if not command_parts:
            print("Error: Invalid command format")
            return

        # Whitelist of allowed commands for security
        allowed_commands = {
            'ls', 'pwd', 'echo', 'cat', 'date', 'whoami', 'id', 'uname',
            'grep', 'find', 'wc', 'head', 'tail', 'sort', 'uniq'
        }

        command_name = command_parts[0].split('/')[-1]  # Get just the command name

        if command_name not in allowed_commands:
            print(f"Error: Command '{command_name}' is not allowed")
            return

        # Execute the command with shell=False for security
        result = subprocess.run(
            command_parts,
            capture_output=True,
            text=True,
            timeout=10
        )

        if result.stdout:
            print(result.stdout)
        if result.stderr:
            print("Error:", result.stderr)

        if result.returncode != 0:
            print(f"Command exited with code {result.returncode}")

    except subprocess.TimeoutExpired:
        print("Error: Command execution timed out")
    except FileNotFoundError:
        print("Error: Command not found")
    except Exception as e:
        print(f"Error: {str(e)}")

