# Whitelist of allowed function calls
ALLOWED_FUNCTIONS = {
    'print', 'len', 'range', 'str', 'int', 'float', 'list', 'dict',
    'tuple', 'set', 'bool', 'abs', 'sum', 'max', 'min', 'sorted',
    'enumerate', 'zip', 'map', 'filter',
}

def is_safe_code(node):
    """
    Recursively check if the AST only contains allowed node types.
    Blocks dangerous operations like imports, function definitions, etc.
    """
    if type(node) not in ALLOWED_AST_NODES:
        return False

    for child in ast.walk(node):
        if type(child) not in ALLOWED_AST_NODES:
            return False

        # Additional check: ensure function calls are to whitelisted functions
        if isinstance(child, ast.Call):
            if isinstance(child.func, ast.Name):
                if child.func.id not in ALLOWED_FUNCTIONS:
                    return False
            elif isinstance(child.func, ast.Attribute):
                # Block attribute access on function calls for safety
                return False

    return True

def safe_eval(code, restricted_globals, restricted_locals):
    """
    Safely evaluate code using AST interpretation instead of eval().
    This avoids using eval() entirely by manually interpreting the AST.
    """
    try:
        tree = ast.parse(code, mode='eval')
    except SyntaxError:
        raise ValueError('Code must be a valid expression')

    if not is_safe_code(tree):
        raise ValueError('Code contains disallowed operations')

    # Manually interpret the AST instead of using eval()
    return _interpret_ast(tree.body, restricted_globals, restricted_locals)

def _interpret_ast(node, globals_dict, locals_dict):
    """
    Safely interpret AST nodes without using eval().
    """
    if isinstance(node, ast.Constant):
        return node.value

    elif isinstance(node, ast.Name):
        if node.id in locals_dict:
            return locals_dict[node.id]
        elif node.id in globals_dict:
            return globals_dict[node.id]
        else:
            raise NameError(f"name '{node.id}' is not defined")

    elif isinstance(node, ast.BinOp):
        left = _interpret_ast(node.left, globals_dict, locals_dict)
        right = _interpret_ast(node.right, globals_dict, locals_dict)
        op = _get_operator(node.op)
        return op(left, right)

    elif isinstance(node, ast.UnaryOp):
        operand = _interpret_ast(node.operand, globals_dict, locals_dict)
        op = _get_unary_operator(node.op)
        return op(operand)

    elif isinstance(node, ast.Compare):
        left = _interpret_ast(node.left, globals_dict, locals_dict)
        result = True
        for op, comparator in zip(node.ops, node.comparators):
            right = _interpret_ast(comparator, globals_dict, locals_dict)
            comp_op = _get_comparator(op)
            result = result and comp_op(left, right)
            left = right
        return result

    elif isinstance(node, ast.Call):
        func = _interpret_ast(node.func, globals_dict, locals_dict)
        args = [_interpret_ast(arg, globals_dict, locals_dict) for arg in node.args]
        kwargs = {kw.arg: _interpret_ast(kw.value, globals_dict, locals_dict) for kw in node.keywords}
        return func(*args, **kwargs)

    elif isinstance(node, ast.List):
        return [_interpret_ast(elt, globals_dict, locals_dict) for elt in node.elts]

    elif isinstance(node, ast.Tuple):
        return tuple(_interpret_ast(elt, globals_dict, locals_dict) for elt in node.elts)

    elif isinstance(node, ast.Dict):
        keys = [_interpret_ast(k, globals_dict, locals_dict) for k in node.keys]
        values = [_interpret_ast(v, globals_dict, locals_dict) for v in node.values]
        return dict(zip(keys, values))

    elif isinstance(node, ast.Set):
        return {_interpret_ast(elt, globals_dict, locals_dict) for elt in node.elts}

    elif isinstance(node, ast.IfExp):
        test = _interpret_ast(node.test, globals_dict, locals_dict)
        if test:
            return _interpret_ast(node.body, globals_dict, locals_dict)
        else:
            return _interpret_ast(node.orelse, globals_dict, locals_dict)

    elif isinstance(node, ast.Subscript):
        value = _interpret_ast(node.value, globals_dict, locals_dict)
        slice_val = _interpret_ast(node.slice, globals_dict, locals_dict)
        return value[slice_val]

    elif isinstance(node, ast.Attribute):
        value = _interpret_ast(node.value, globals_dict, locals_dict)
        return getattr(value, node.attr)

    else:
        raise ValueError(f"Unsupported AST node type: {type(node).__name__}")

def _get_operator(op):
    """Get the operator function for binary operations."""
    ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
        ast.BitOr: operator.or_,
        ast.BitXor: operator.xor,
        ast.BitAnd: operator.and_,
        ast.MatMult: operator.matmul,
    }
    return ops[type(op)]

def _get_unary_operator(op):
    """Get the operator function for unary operations."""
    ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
        ast.Invert: operator.invert,
    }
    return ops[type(op)]

def _get_comparator(op):
    """Get the comparator function for comparison operations."""
    ops = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda x, y: x in y,
        ast.NotIn: lambda x, y: x not in y,
    }
    return ops[type(op)]

