        code = request.args.get('code', '')

        if not code:
            return {'error': 'No code provided'}, 400

        # Create a restricted execution environment
        restricted_globals = {
            'print': print,
            'len': len,
            'range': range,
            'str': str,
            'int': int,
            'float': float,
            'list': list,
            'dict': dict,
            'tuple': tuple,
            'set': set,
