            'max': max,
            'min': min,
            'sorted': sorted,
            'enumerate': enumerate,
            'zip': zip,
            'map': map,
            'filter': filter,
        }
        restricted_locals = {}

        # Capture output
        old_stdout = sys.stdout
        sys.stdout = StringIO()

        try:
            result = safe_eval(code, restricted_globals, restricted_locals)
            output = sys.stdout.getvalue()
        except ValueError as e:
            sys.stdout = old_stdout
            return {'error': str(e)}, 400
        except SyntaxError as e:
            sys.stdout = old_stdout
            return {'error': f'Syntax error: {str(e)}'}, 400
        finally:
            sys.stdout = old_stdout

        return {
            'output': output,
            'result': str(result) if result is not None else '',
            'status': 'success'
        }, 200

    except Exception as e:
